// rowLinkAttrs returns templ.Attributes for clickable linked rows.
// Behavior depends on Row.LinkMode:
//   - LinkSPA (default): swaps #main-content-area via HTMX
//   - LinkBoost: swaps full <body> via HTMX (like hx-boost, avoids white flash)
//   - LinkFull: plain JS navigation (window.location.href), no HTMX
func rowLinkAttrs(row Row) templ.Attributes {
	auxclick := fmt.Sprintf("if(event.button===1){event.preventDefault();window.open('%s','_blank')}", row.Link)

	if row.LinkMode == LinkFull {
		return templ.Attributes{
			"onclick":    fmt.Sprintf("window.location.href='%s'", row.Link),
			"onauxclick": auxclick,
		}
	}

	attrs := templ.Attributes{
		"hx-get":      row.Link,
		"hx-push-url": "true",
		"onauxclick":  auxclick,
	}
	if row.LinkMode == LinkBoost {
		attrs["hx-target"] = "body"
		attrs["hx-select"] = "body"
		attrs["hx-swap"] = "outerHTML"
	} else {
		// SPA mode (default) — swap only the content area
		attrs["hx-target"] = "#main-content-area"
		attrs["hx-swap"] = "innerHTML"
	}
	return attrs
}

func interactiveRowClasses(row Row) string {
	if row.IsActionable() {
		return " cursor-pointer hover:bg-surface-alt/30 dark:hover:bg-surface-dark-alt/30"
	}
	return ""
}

// rowActionAttrs returns HTMX/JS attributes for row click actions (OnClick, HXGet, HXPost).
// Link and Expandable are handled separately in the template.
func rowActionAttrs(row Row) templ.Attributes {
	if row.Link != "" {
		return nil // handled by rowLinkAttrs
	}
	if row.OnClick != "" {
		// Use onclick (not x-on:click) so it works without an Alpine x-data ancestor on the table container.
		return templ.Attributes{
			"onclick": row.OnClick,
		}
	}
	if row.HXGet != "" {
		attrs := templ.Attributes{
			"hx-get":    row.HXGet,
			"hx-target": row.HXTarget,
		}
		if row.HXSwap != "" {
			attrs["hx-swap"] = row.HXSwap
		} else {
			attrs["hx-swap"] = "innerHTML"
		}
		return attrs
	}
	if row.HXPost != "" {
		attrs := templ.Attributes{
			"hx-post":   row.HXPost,
			"hx-target": row.HXTarget,
		}
		if row.HXSwap != "" {
			attrs["hx-swap"] = row.HXSwap
		} else {
			attrs["hx-swap"] = "innerHTML"
		}
		return attrs
	}
	return nil
}

